import { Amplitude } from "amplitude-node";

// NOTE: This is a Node.js client, so you can use it for sending events from the server side to Amplitude.
export default function AmplitudeClient() {
  const amplitudeClient = new Amplitude(process.env.NEXT_PUBLIC_AMPLITUDE_KEY!, {
    host: process.env.NEXT_PUBLIC_AMPLITUDE_HOST,
    flushAt: 1,
    flushInterval: 0,
  });
  return amplitudeClient;
}
